SELECT e.employeeid, e.firstname, e.lastname, o.orderid, o.orderdate, o.shippeddate, od.productid, p.productname, od.quantity FROM employees e JOIN orders o ON e.employeeid = o.employeeid JOIN "order details" od ON o.orderid = od.orderid JOIN products p ON od.productid = p.productid JOIN categories c ON p.categoryid = c.categoryid JOIN employeeterritories et ON e.employeeid = et.employeeid JOIN territories t ON et.territoryid = t.territoryid WHERE c.categoryname = 'Beverages' AND strftime('%Y', o.shippeddate) = '1997' AND strftime('%m', o.shippeddate) BETWEEN '01' AND '03' AND t.regionid = 1 AND e.title = 'Sales Representative'
